#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y, Z;
        scanf("%lld %lld %lld", &X, &Y, &Z);
        if (X >= Y || X + 2 * Z >= Y) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

